import{_ as e,o as a,c as l,a3 as n}from"./chunks/framework.DACwFHq9.js";const x=JSON.parse('{"title":"🤖 智能体 (Agent) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/index.md","filePath":"user-guide/tools/llm-chat/agents/index.md","lastUpdated":1778239080000}'),r={name:"user-guide/tools/llm-chat/agents/index.md"};function s(i,t,d,g,o,h){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="🤖-智能体-agent-概览" tabindex="-1">🤖 智能体 (Agent) 概览 <a class="header-anchor" href="#🤖-智能体-agent-概览" aria-label="Permalink to &quot;🤖 智能体 (Agent) 概览&quot;">​</a></h1><p>智能体 (Agent) 是 LLM Chat 的核心概念——它是<strong>角色设定 + 模型参数 + 工具权限 + 预设消息</strong>的完整配置包。你可以在不同 Agent 之间快速切换，以适应不同的对话场景。</p><h2 id="什么是-agent" tabindex="-1">什么是 Agent？ <a class="header-anchor" href="#什么是-agent" aria-label="Permalink to &quot;什么是 Agent？&quot;">​</a></h2><p>一个典型的 Agent 包含以下核心组件：</p><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">说明</th><th style="text-align:left;">详细指南</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>🆔 基本信息</strong></td><td style="text-align:left;">名称、图标、描述、分类标签</td><td style="text-align:left;"><a href="./editor-guide#1-基础设定-basic">基础设定</a></td></tr><tr><td style="text-align:left;"><strong>👤 角色设定</strong></td><td style="text-align:left;">系统提示词、角色人格定义、预设消息</td><td style="text-align:left;"><a href="./parameters">参数配置</a></td></tr><tr><td style="text-align:left;"><strong>⚙️ 模型参数</strong></td><td style="text-align:left;">关联的服务渠道 (Profile)、模型 ID、Temperature 等</td><td style="text-align:left;"><a href="./parameters">参数配置</a></td></tr><tr><td style="text-align:left;"><strong>🔧 工具配置</strong></td><td style="text-align:left;">工具调用开关、自动批准规则、并行执行控制</td><td style="text-align:left;"><a href="./../tool-calling/index">工具调用</a></td></tr><tr><td style="text-align:left;"><strong>📖 关联资源</strong></td><td style="text-align:left;">世界书、快捷操作、用户档案绑定</td><td style="text-align:left;"><a href="./parameters#关联资源">关联资源</a></td></tr><tr><td style="text-align:left;"><strong>🧩 扩展配置</strong></td><td style="text-align:left;">插件扩展启用状态、环境增强</td><td style="text-align:left;"><a href="./editor-guide#6-环境增强-environment">环境增强</a></td></tr><tr><td style="text-align:left;"><strong>🎨 输出表现</strong></td><td style="text-align:left;">渲染样式、正则替换、视觉化指南</td><td style="text-align:left;"><a href="./editor-guide#7-输出与显示-output">输出与显示</a></td></tr></tbody></table><h2 id="切换-agent" tabindex="-1">切换 Agent <a class="header-anchor" href="#切换-agent" aria-label="Permalink to &quot;切换 Agent&quot;">​</a></h2><p>系统提供了多种方式在不同智能体之间无缝切换：</p><ul><li><strong>左侧面板</strong>: 点击 Agent 列表中的条目即可立即切换当前会话的 Agent。</li><li><strong>快速切换菜单</strong>: 在消息输入框上方点击 🤖 图标，呼出快速切换下拉菜单。</li><li><strong>自动切换策略</strong>: 当你切换到某个会话（Session）时，系统会自动切换到该会话最后一次使用的 Agent。</li></ul><h2 id="数据隔离与安全性" tabindex="-1">数据隔离与安全性 <a class="header-anchor" href="#数据隔离与安全性" aria-label="Permalink to &quot;数据隔离与安全性&quot;">​</a></h2><p>为了保证不同角色扮演或任务场景的独立性，每个 Agent 拥有独立的数据存储空间：</p><ol><li><strong>配置隔离</strong>: 所有的提示词、参数和变量均独立存储。</li><li><strong>资产隔离</strong>: 每个 Agent 拥有独立的 <a href="./assets">资产目录</a>，避免不同角色间的媒体资源混淆。</li><li><strong>安全删除</strong>: 当你删除一个 Agent 时，其配置文件和关联资产目录会被移入系统回收站，而非直接永久抹除，方便误删恢复。</li></ol><hr><h3 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h3><ul><li><a href="./editor-guide">创建与编辑 Agent</a></li><li><a href="./parameters">配置模型与预设消息</a></li><li><a href="./assets">管理 Agent 资产</a></li></ul>',14)])])}const u=e(r,[["render",s]]);export{x as __pageData,u as default};
